import{_ as t,o,c as n,a8 as a}from"./chunks/framework.DvHWw5tv.js";const g=JSON.parse('{"title":"useSelectComputed","description":"","frontmatter":{},"headers":[],"relativePath":"en/design/hooks/useSelect.md","filePath":"en/design/hooks/useSelect.md"}'),i={name:"en/design/hooks/useSelect.md"};function l(d,e,r,s,c,p){return o(),n("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1776104037000"},[...e[0]||(e[0]=[a('<h1 id="useselectcomputed" tabindex="-1">useSelectComputed <a class="header-anchor" href="#useselectcomputed" aria-label="Permalink to “useSelectComputed”">​</a></h1><h3 id="useselectcomputed-generic-dropdown-selector-interaction-hook" tabindex="-1">useSelectComputed: Generic Dropdown Selector Interaction Hook <a class="header-anchor" href="#useselectcomputed-generic-dropdown-selector-interaction-hook" aria-label="Permalink to “useSelectComputed: Generic Dropdown Selector Interaction Hook”">​</a></h3><h2 id="pain-points" tabindex="-1">Pain Points <a class="header-anchor" href="#pain-points" aria-label="Permalink to “Pain Points”">​</a></h2><p>Dropdown selectors (Select, Dropdown, etc.) are highly interactive form controls, yet their core interaction logic is heavily duplicated across multiple components:</p><ul><li>Need to manage dropdown panel visibility state</li><li>Handle focus state (<code>focused</code>) for styling and keyboard interaction</li><li>Implement click-outside-to-close behavior</li><li>Prevent all interactions when disabled</li><li>Sync internal state when external <code>v-model</code> changes</li><li>Event listeners must be properly added and removed within component lifecycle to avoid memory leaks</li></ul><p>If each Select-like component implements this logic independently, it leads to redundant code and common issues such as:</p><ul><li>Click-outside failure or false triggers</li><li>Memory leaks due to improperly removed event listeners</li><li>Inconsistent handling of disabled states</li><li>Focus and dropdown states out of sync</li></ul><h2 id="design-goals" tabindex="-1">Design Goals <a class="header-anchor" href="#design-goals" aria-label="Permalink to “Design Goals”">​</a></h2><p>The goal of <code>useSelect</code> is to <strong>provide a lightweight, generic, and reusable dropdown interaction management solution</strong>, completely abstracting core interactive logic like visibility, focus, and click-outside for Select-like components. Components only need to focus on option rendering and value selection logic.</p><h2 id="core-features" tabindex="-1">Core Features <a class="header-anchor" href="#core-features" aria-label="Permalink to “Core Features”">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td><strong>Reactive Dropdown State</strong></td><td><code>dropdownVisible</code> is a <code>ref&lt;boolean&gt;</code> for real-time panel visibility control</td></tr><tr><td><strong>Focus State Management</strong></td><td><code>isFocused</code> supports styling (e.g., border highlight) and keyboard navigation foundation</td></tr><tr><td><strong>Click-Outside Auto-Close</strong></td><td>Implemented via global <code>click</code> event listener, using selector <code>.select-e</code> as basis (customizable)</td></tr><tr><td><strong>Disabled State Safety</strong></td><td>All interaction entry points (e.g., toggle) check <code>disabled</code> first, preventing unintended operations</td></tr><tr><td><strong>Automatic Lifecycle Management</strong></td><td>Listener added on <code>onMounted</code>, automatically removed on <code>onUnmounted</code>; no manual handling required</td></tr><tr><td><strong>External modelValue Watching</strong></td><td>Reserved <code>watch</code> position for syncing selected label or other derived states</td></tr><tr><td><strong>Generic Type Safety</strong></td><td>Supports <code>modelValue</code> of any type <code>T</code>, perfectly adapting to strings, numbers, objects, etc.</td></tr></tbody></table><h2 id="design-value" tabindex="-1">Design Value <a class="header-anchor" href="#design-value" aria-label="Permalink to “Design Value”">​</a></h2><p><code>useSelect</code> completely strips away the most error-prone and repetitive interaction control logic from Select-like components, making component implementations clean and reliable:</p><ul><li>All dropdown components (Select, Cascader, TreeSelect, etc.) can share the same interaction behavior, ensuring a highly consistent experience</li><li>Click-outside logic is centrally managed, avoiding repeated implementations and missed cleanup</li><li>Focus and disabled states are handled uniformly, supporting accessibility and visual feedback</li><li>Component templates only need to focus on &quot;presentation&quot; and &quot;option selection&quot;; interaction details are fully delegated to the Hook</li><li>Clear space reserved for future extensions (e.g., keyboard navigation, search filtering)</li></ul>',14)])])}const m=t(i,[["render",l]]);export{g as __pageData,m as default};
